import React, { useState, useEffect } from "react";
import axios from "axios";

const AdvisoryForm = () => {
    const [user, setUser] = useState("");
    const [advisory, setAdvisory] = useState("");
    const [advisories, setAdvisories] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    useEffect(() => {
        fetchAdvisories();
    }, []);

    const fetchAdvisories = async () => {
        setLoading(true);
        try {
            const response = await axios.get("http://localhost:5000/api/advisory/getAll");
            setAdvisories(response.data);
        } catch (err) {
            setError("Failed to fetch advisories.");
        } finally {
            setLoading(false);
        }
    };

    const submitAdvisory = async () => {
        if (!user || !advisory) {
            setError("Please enter both name and advisory.");
            return;
        }
        setLoading(true);
        setError("");

        try {
            await axios.post("http://localhost:5000/api/advisory/add", { user, advisory });
            setUser("");
            setAdvisory("");
            fetchAdvisories();
        } catch (err) {
            setError("Failed to submit advisory.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-4xl mx-auto p-6 bg-white shadow-lg rounded-lg flex flex-col md:flex-row gap-6 items-start">
            {/* Form Section */}
            <div className="w-full md:w-1/2 bg-blue-100 p-6 rounded-lg flex flex-col">
                <h2 className="text-xl font-semibold text-gray-700 mb-4 text-center">Submit an Advisory</h2>
                <input
                    type="text"
                    placeholder="Your Name"
                    value={user}
                    onChange={(e) => setUser(e.target.value)}
                    className="w-full p-3 border border-gray-300 rounded-lg mb-3 focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                <textarea
                    placeholder="Write your advisory here..."
                    value={advisory}
                    onChange={(e) => setAdvisory(e.target.value)}
                    className="w-full p-3 border border-gray-300 rounded-lg mb-3 h-24 focus:outline-none focus:ring-2 focus:ring-blue-500"
                ></textarea>
                <button
                    onClick={submitAdvisory}
                    className="w-full bg-blue-500 hover:bg-blue-600 text-white py-2 rounded-lg font-semibold transition"
                >
                    Submit
                </button>
                {loading && <p className="text-gray-500 mt-2">Loading...</p>}
                {error && <p className="text-red-500 mt-2">{error}</p>}
            </div>
            
            {/* Advisories List */}
            <div className="w-full md:w-1/2 p-6 rounded-lg border border-gray-200 bg-gray-50 overflow-y-auto max-h-96 flex flex-col">
                <h3 className="text-lg font-semibold text-gray-700 mb-4">Recent Advisories</h3>
                {advisories.length === 0 ? (
                    <p className="text-gray-500">No advisories yet.</p>
                ) : (
                    <ul className="space-y-3">
                        {advisories.map((adv, index) => (
                            <li key={index} className="bg-white p-4 rounded-lg shadow text-gray-700">
                                <strong className="text-blue-500">{adv.user}</strong>: {adv.advisory}
                            </li>
                        ))}
                    </ul>
                )}
            </div>
        </div>
    );
};

export default AdvisoryForm;
